// ---------------------------------

export interface MappingContext {
  subQuestionIndex: number
  options?: string[]
  correctAnswer?: number | null
  acceptedAnswers?: string[]
  geometryPayload?: Record<string, unknown>
  axisPayload?: Record<string, unknown>
