/**
 * V3 Converter - Asset Handler
 *
 * Handles creation of ExerciseAssets for SVG and Media blocks.
 * Uses privileged execution for internal asset writes (NFR-003).
 *
 * @fileType utility
 * @domain conversion
 * @pattern asset-management
 */

import type { Payload } from 'payload'

// ---------------------------------
// Types
// ---------------------------------

export interface AssetCreationResult {
  success: boolean
  assetId?: string
  error?: string
}

export interface AssetCreationParams {
  payload: Payload
  type: 'svg' | 'media'
  content: string
  mimeType?: string
  correlationId: string
  // Optional req for transaction safety when called from hooks
  req?: {
    payload: Payload
  }
}

// ---------------------------------
// Asset Handler Functions
// ---------------------------------

/**
 * Create an SVG asset in ExerciseAssets collection.
 * Uses privileged execution (overrideAccess: true) for internal writes.
 */
export async function createSvgAsset(params: AssetCreationParams): Promise<AssetCreationResult> {
  const { payload, content, mimeType = 'image/svg+xml', correlationId, req } = params

  try {
    // Use req.payload if available (for hook context), otherwise use direct payload
    const effectivePayload = req?.payload || payload

    const result = await effectivePayload.create({
      collection: 'exercise-assets',
      data: {
        type: 'svg',
        svgContent: content,
        mimeType,
        source: 'conversion',
        correlationId,
      },
      overrideAccess: true, // Privileged internal write
    })

    return {
      success: true,
      assetId: result.id,
    }
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error creating SVG asset',
    }
  }
}

/**
 * Create a media asset in ExerciseAssets collection.
 * For URL-based media, stores the reference; for file uploads, processes them.
 */
export async function createMediaAsset(params: AssetCreationParams): Promise<AssetCreationResult> {
  const { payload, content, mimeType = 'image/png', correlationId, req } = params

  try {
    // Use req.payload if available (for hook context), otherwise use direct payload
    const effectivePayload = req?.payload || payload

    // Determine if content is a URL or base64 data
    const isUrl = content.startsWith('http://') || content.startsWith('https://')
    const isDataUri = content.startsWith('data:')

    if (isUrl) {
      // Store URL reference
      const result = await effectivePayload.create({
        collection: 'exercise-assets',
        data: {
          type: 'media',
          url: content,
          mimeType,
          source: 'conversion',
          correlationId,
        },
        overrideAccess: true, // Privileged internal write
      })

      return {
        success: true,
        assetId: result.id,
      }
    }

    if (isDataUri) {
      // Extract data from data URI
      const match = content.match(/^data:([^;]+);base64,(.+)$/)
      if (match) {
        const extractedMimeType = match[1]
        const base64Data = match[2]

        const result = await effectivePayload.create({
          collection: 'exercise-assets',
          data: {
            type: 'media',
            base64Data,
            mimeType: extractedMimeType,
            source: 'conversion',
            correlationId,
          },
          overrideAccess: true, // Privileged internal write
        })

        return {
          success: true,
          assetId: result.id,
        }
      }
    }

    // For raw content, store as-is
    const result = await effectivePayload.create({
      collection: 'exercise-assets',
      data: {
        type: 'media',
        rawContent: content,
        mimeType,
        source: 'conversion',
        correlationId,
      },
      overrideAccess: true, // Privileged internal write
    })

    return {
      success: true,
      assetId: result.id,
    }
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error creating media asset',
    }
  }
}

/**
 * Handle asset creation failure by producing a fallback block.
 * Returns a rich_text block with a safe reference to the original content.
 */
export function handleAssetFailure(
  segmentType: 'svg' | 'media',
  content: string,
  correlationId: string,
): { fallbackContent: string; warningMessage: string } {
  // Produce a non-dropping fallback representation
  const fallbackContent =
    segmentType === 'svg'
      ? `[SVG content - asset creation failed for correlation: ${correlationId}]`
      : `[Media: ${content.substring(0, 50)}${content.length > 50 ? '...' : ''}]`

  const warningMessage = `Asset creation failed for ${segmentType} (correlation: ${correlationId}), using fallback representation`

  return {
    fallbackContent,
    warningMessage,
  }
}

/**
 * Create asset with automatic type detection.
 */
export async function createAsset(params: AssetCreationParams): Promise<AssetCreationResult> {
  const { type } = params

  if (type === 'svg') {
    return createSvgAsset(params)
  }

  return createMediaAsset(params)
}

