    stem: extraction.stem,
    subQuestions: extraction.subQuestions.map((sq) => ({
      prompt: sq.prompt,
      type: sq.type,
      options: sq.options,
      correctAnswer: sq.correctAnswer,
      acceptedAnswers: sq.acceptedAnswers,
      diagramDescription: sq.diagramDescription,
