  const lines = content.split('\n')
  let optionCount = 0

  for (const line of lines) {
    if (OPTIONS_PATTERN.test(line.trim())) {
      optionCount++
    }
  }

  // Consider it options if we have 2+ lines with option markers
  return optionCount >= 2
