    const match = content.match(/"correctAnswers"\s*:\s*\[([^\]]+)\]/i)
    if (match) {
      const answers = match[1].split(',').map((s) => s.trim())
      return answers.length > 1
    }
  }

  if (/"correct"\s*:\s*\[/i.test(content)) {
    const match = content.match(/"correct"\s*:\s*\[([^\]]+)\]/i)
    if (match) {
      const answers = match[1].split(',').map((s) => s.trim())
      return answers.length > 1
    }
  }

  return false
