 */
function createEmptyFeatures(): DetectedFeatures {
  return {
    hasOptions: false,
    hasMultipleCorrect: false,
    hasTable: false,
    hasMatching: false,
    hasSvg: false,
    hasHtml: false,
    hasMedia: false,
    hasGeometry: false,
    hasAxisGraph: false,
    hasLatex: false,
    hasRichText: true,
  }
}

