  try {
    const geometry = JSON.parse(content)
    const block = QuestionGeometryBlockSchema.parse({
      id: nanoid(),
      type: 'question_geometry',
      prompt: {
        type: 'rich_text',
        format: 'md-math-v1',
        value: '',
