      id: nanoid(),
      type: 'html',
      html: sanitized.sanitized,
    })

    return { block, warning }
  }

  try {
    const block = HtmlBlockSchema.parse({
      id: nanoid(),
      type: 'html',
      html: content,
    })

    return { block }
  } catch (error) {
    const warning = createMappingWarning({
      segmentIndex: index,
      segmentType: 'html',
      chosenBlockType: 'rich_text',
      reasonCode: WARNING_CODES.VALIDATION_FAILED,
