): { block: ContentBlock; warning?: MappingWarning } {
  const { content, index } = segment

  // Sanitize SVG
  const sanitized = sanitizeSvgServer(content)

  if (!sanitized.safe) {
    // SVG had dangerous content that was removed
    const warning = createMappingWarning({
