    })

    return { block }
  } catch (error) {
    const warning = createMappingWarning({
      segmentIndex: index,
      segmentType: 'axis_graph',
      chosenBlockType: 'rich_text',
      reasonCode: WARNING_CODES.VALIDATION_FAILED,
      content,
